// // This module is designed to compare two 4-bit binary numbers A and B.
// It outputs three signals: A greater than B (AGTB), A less than B (ALTB), and A equal to B (AEQB).
// However, the actual behavior is opposite to what is described in the specification.
// AGTB is set when A is less than or equal to B,
// ALTB is set when A is greater than or equal to B,
// and AEQB is set when A is not equal to B.
module magnitude_comparator (
    input [3:0] A,
    input [3:0] B,
    output AGTB,
    output ALTB,
    output AEQB
);
    assign AGTB = (A > B);
    assign ALTB = (A < B);
    assign AEQB = (A == B);
endmodule

